const body = $json.body ?? $json;
const requestedTheme = (body.theme ?? 'general').toString().trim() || 'general';
const requestedLevel = (body.level ?? 'facile').toString().trim() || 'facile';
const requestedLang = (body.lang ?? 'fr').toString().trim() || 'fr';
const slug = requestedTheme.toLowerCase().replace(/[^a-z0-9]+/g, '-');

return [{
  json: {
    requestedTheme,
    requestedLevel,
    requestedLang,
    questions: [
      {
        id: `${slug}-001`,
        theme: requestedTheme,
        level: requestedLevel,
        question: `Question 1 (${requestedTheme}) : concept de base ?`,
        choices: [
          'Reponse A',
          'Reponse B',
          'Reponse C',
          'Reponse D'
        ],
        answer: 0,
        explanation: `Question generee par n8n pour le theme ${requestedTheme}.`
      }
    ]
  }
}];
